index.styles:
* { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: -apple-system, BlinkMacSystemFont, 'Hiragino Kaku Gothic ProN', 'Hiragino Sans', Meiryo, sans-serif; color: #333; line-height: 1.8; background: #feffff; }
    .hero { background: #333; color: #feffff; padding: 100px 20px; text-align: center; position: relative; overflow: hidden; }
    .hero::before { content: ''; position: absolute; inset: 0; background: linear-gradient(135deg, rgba(26,35,126,0.25) 0%, transparent 50%, rgba(19,149,186,0.12) 100%); }
    .hero-inner { position: relative; max-width: 720px; margin: 0 auto; }
    .hero h1 { font-size: 2.6rem; font-weight: 800; margin-bottom: 0.3rem; }
    .hero h1 small { font-size: 1.15rem; font-weight: 400; display: block; color: #8fa4ff; margin-top: 0.3rem; }
    .hero .eyebrow { display: inline-block; background: rgba(255,255,255,0.1); border: 1px solid rgba(255,255,255,0.2); border-radius: 100px; padding: 6px 18px; font-size: 0.8rem; margin-bottom: 1.5rem; color: #8fa4ff; }
    .hero .desc { font-size: 1rem; opacity: 0.9; max-width: 600px; margin: 1.5rem auto 0; }
    .hero .badges { display: flex; justify-content: center; gap: 10px; margin-top: 2rem; flex-wrap: wrap; }
    .hero .badge { background: rgba(26,35,126,0.35); border: 1px solid rgba(143,164,255,0.35); color: #c5d0ff; padding: 6px 14px; border-radius: 20px; font-size: 0.8rem; }
    .level-visual { display: flex; justify-content: center; gap: 8px; margin-top: 2rem; flex-wrap: wrap; }
    .level-chip { padding: 8px 12px; border-radius: 8px; font-size: 0.75rem; font-weight: 600; color: #fff; }
    section { padding: 80px 20px; }
    section:nth-child(even) { background: #f8f9fa; }
    .container { max-width: 800px; margin: 0 auto; }
    .section-title { font-size: 1.6rem; font-weight: 700; text-align: center; margin-bottom: 0.5rem; }
    .section-subtitle { text-align: center; color: #888; font-size: 0.95rem; margin-bottom: 3rem; }
    .insight-card { background: #fff; border-radius: 16px; padding: 32px; border: 1px solid #eee; box-shadow: 0 2px 8px rgba(0,0,0,0.04); margin-bottom: 20px; }
    .insight-card h3 { font-size: 1.1rem; color: #1a237e; margin-bottom: 0.8rem; }
    .insight-card p { font-size: 0.95rem; color: #555; }
    .features-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 20px; }
    .feature-card { background: #fff; border-radius: 12px; padding: 28px; border: 1px solid #eee; transition: transform 0.2s; }
    .feature-card:hover { transform: translateY(-2px); box-shadow: 0 4px 16px rgba(0,0,0,0.06); }
    .feature-card .icon { font-size: 2rem; margin-bottom: 0.8rem; }
    .feature-card h3 { font-size: 1rem; margin-bottom: 0.5rem; }
    .feature-card p { font-size: 0.85rem; color: #666; line-height: 1.6; }
    .screenshot-gallery { display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 20px; }
    .screenshot-item { border-radius: 12px; overflow: hidden; box-shadow: 0 2px 12px rgba(0,0,0,0.08); background: #fff; }
    .screenshot-item img { width: 100%; height: auto; display: block; }
    .screenshot-label { display: block; padding: 12px 16px; font-size: 0.85rem; color: #555; text-align: center; font-weight: 600; }
    .pricing-grid { display: flex; justify-content: center; flex-wrap: wrap; }
    .pricing-card { background: #fff; border-radius: 16px; padding: 32px; width: 300px; border: 2px solid #1a237e; text-align: center; box-shadow: 0 4px 20px rgba(26,35,126,0.1); }
    .pricing-card .plan-label { display: inline-block; background: #1a237e; color: #fff; font-size: 0.75rem; padding: 2px 12px; border-radius: 100px; font-weight: 600; margin-bottom: 0.5rem; }
    .pricing-card .plan-name { font-size: 1rem; font-weight: 700; }
    .pricing-card .plan-price { font-size: 2rem; font-weight: 800; margin: 1rem 0; }
    .pricing-card .plan-price .unit { font-size: 0.9rem; font-weight: 400; color: #888; }
    .pricing-card .plan-desc { font-size: 0.85rem; color: #666; margin-bottom: 1.5rem; }
    .pricing-card .plan-features { text-align: left; list-style: none; }
    .pricing-card .plan-features li { font-size: 0.85rem; padding: 6px 0 6px 20px; border-bottom: 1px solid #f0f0f0; position: relative; }
    .pricing-card .plan-features li::before { content: '✓'; position: absolute; left: 0; color: #15b788; font-weight: 700; }
    .cta-section { text-align: center; }
    .cta-section p { font-size: 1.05rem; margin-bottom: 1.5rem; color: #555; }
    .cta-section .btn { display: inline-block; background: #1a237e; color: #fff; text-decoration: none; padding: 16px 40px; border-radius: 10px; font-weight: 700; }
    .cta-section .btn.secondary { background: #1395ba; margin-left: 12px; }
    .cta-section .store-badges { display: flex; justify-content: center; gap: 16px; margin-top: 1.5rem; flex-wrap: wrap; }
    .cta-section .store-badge { display: inline-block; background: #333; color: #fff; padding: 12px 24px; border-radius: 8px; font-size: 0.9rem; font-weight: 600; text-decoration: none; transition: background 0.2s, transform 0.15s; }
    .cta-section .store-badge:hover { background: #111; transform: translateY(-1px); }
    .cta-section .micro { margin-top: 1rem; font-size: 0.8rem; color: #999; }
    footer { text-align: center; padding: 32px 20px; border-top: 1px solid #eee; font-size: 0.85rem; color: #888; }
    footer a { color: #1395ba; text-decoration: none; }
    footer .links a { margin: 0 12px; }
    @media (max-width: 640px) { .hero h1 { font-size: 2rem; } .pricing-card { width: 100%; max-width: 320px; } }

